import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
BLOCK_SIZE = 30
BOARD_WIDTH = 10
BOARD_HEIGHT = 20
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self, shape):
        self.shape = shape
        self.color = COLORS[random.randint(1, len(COLORS) - 1)]
        self.x = BOARD_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Board:
    def __init__(self):
        self.grid = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.score = 0

    def add_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + y][tetromino.x + x] = 1

    def clear_lines(self):
        lines_cleared = 0
        for i in range(len(self.grid) - 1, -1, -1):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0 for _ in range(BOARD_WIDTH)])
                lines_cleared += 1
        self.score += lines_cleared * 100

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.boards = [Board() for _ in range(3)]
        self.current_tetrominos = [self.new_tetromino() for _ in range(3)]
        self.running = True
        self.scores = [0, 0, 0]

    def new_tetromino(self):
        return Tetromino(random.choice(SHAPES))

    def draw_board(self, board, offset_x, offset_y):
        for y, row in enumerate(board.grid):
            for x, value in enumerate(row):
                if value:
                    pygame.draw.rect(self.screen, COLORS[value], 
                                     (offset_x + x * BLOCK_SIZE, offset_y + y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def run(self):
        while self.running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False

            self.screen.fill((0, 0, 0))
            for i, board in enumerate(self.boards):
                self.draw_board(board, i * (SCREEN_WIDTH // 3), 0)
                self.scores[i] = board.score

            for i in range(3):
                if self.current_tetrominos[i].y < BOARD_HEIGHT - len(self.current_tetrominos[i].shape):
                    self.current_tetrominos[i].y += 1
                else:
                    self.boards[i].add_tetromino(self.current_tetrominos[i])
                    self.boards[i].clear_lines()
                    self.current_tetrominos[i] = self.new_tetromino()

            pygame.display.flip()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

import pygame
import random

# Constants
SCREEN_WIDTH = 300
SCREEN_HEIGHT = 600
BLOCK_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // BLOCK_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // BLOCK_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = COLORS[SHAPES.index(self.shape) + 1]
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Tetris:
    def __init__(self):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = [0, 0, 0]
        self.player_contributions = [0, 0, 0]
        self.current_player = 0

    def valid_position(self, shape, offset_x, offset_y):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    if (x + offset_x < 0 or x + offset_x >= GRID_WIDTH or
                            y + offset_y >= GRID_HEIGHT or
                            self.grid[y + offset_y][x + offset_x]):
                        return False
        return True

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_tetromino.color
        self.clear_lines()
        self.current_tetromino = Tetromino()

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.grid) if all(row)]
        for i in lines_to_clear:
            self.grid.pop(i)
            self.grid.insert(0, [0] * GRID_WIDTH)
            self.score[self.current_player] += 100
            self.player_contributions[self.current_player] += 100

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def drop(self):
        if self.valid_position(self.current_tetromino.shape, self.current_tetromino.x, self.current_tetromino.y + 1):
            self.current_tetromino.y += 1
        else:
            self.merge_tetromino()
            self.switch_player()

    def move(self, dx):
        if self.valid_position(self.current_tetromino.shape, self.current_tetromino.x + dx, self.current_tetromino.y):
            self.current_tetromino.x += dx

    def rotate(self):
        self.current_tetromino.rotate()
        if not self.valid_position(self.current_tetromino.shape, self.current_tetromino.x, self.current_tetromino.y):
            self.current_tetromino.rotate()  # Rotate back if invalid

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.tetris = Tetris()
        self.running = True

    def draw_grid(self):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = self.tetris.grid[y][x] if self.tetris.grid[y][x] else (255, 255, 255)
                pygame.draw.rect(self.screen, color, (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 0)

    def draw_tetromino(self):
        for y, row in enumerate(self.tetris.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, self.tetris.current_tetromino.color,
                                     ((self.tetris.current_tetromino.x + x) * BLOCK_SIZE,
                                      (self.tetris.current_tetromino.y + y) * BLOCK_SIZE,
                                      BLOCK_SIZE, BLOCK_SIZE), 0)

    def draw_scores(self):
        font = pygame.font.Font(None, 36)
        for i in range(3):
            score_text = font.render(f'Player {i + 1}: {self.tetris.score[i]}', True, (0, 0, 0))
            self.screen.blit(score_text, (10, 10 + i * 30))

    def run(self):
        while self.running:
            self.screen.fill((255, 255, 255))
            self.draw_grid()
            self.draw_tetromino()
            self.draw_scores()
            pygame.display.flip()
            self.tetris.drop()
            self.clock.tick(FPS)

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT:
                        self.tetris.move(-1)
                    if event.key == pygame.K_RIGHT:
                        self.tetris.move(1)
                    if event.key == pygame.K_DOWN:
                        self.tetris.drop()
                    if event.key == pygame.K_UP:
                        self.tetris.rotate()

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

