import random

# Constants
SCREEN_WIDTH = 300
SCREEN_HEIGHT = 600
BLOCK_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // BLOCK_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // BLOCK_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self, shape):
        self.shape = shape
        self.color = COLORS[random.randint(1, len(COLORS) - 1)]
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Grid:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0 for _ in range(GRID_WIDTH)])
                lines_cleared += 1
        return lines_cleared

    def add_tetromino(self, tetromino):
        for i, row in enumerate(tetromino.shape):
            for j, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + i][tetromino.x + j] = 1

    def is_valid_position(self, tetromino):
        for i, row in enumerate(tetromino.shape):
            for j, value in enumerate(row):
                if value:
                    if (tetromino.x + j < 0 or tetromino.x + j >= GRID_WIDTH or
                            tetromino.y + i >= GRID_HEIGHT or
                            self.grid[tetromino.y + i][tetromino.x + j]):
                        return False
        return True

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.score = 0

    def update_score(self, lines_cleared):
        self.score += lines_cleared

class TetrisGame:
    def __init__(self):
        self.grid = Grid()
        self.players = [Player(i) for i in range(3)]
        self.current_tetromino = self.new_tetromino()
        self.clock = pygame.time.Clock()
        self.running = True

    def new_tetromino(self):
        return Tetromino(random.choice(SHAPES))

    def run(self):
        pygame.init()
        screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris for 3 Players")

        while self.running:
            self.handle_events()
            self.update()
            self.render(screen)
            self.clock.tick(FPS)

        pygame.quit()

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False

    def update(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_position(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.grid.add_tetromino(self.current_tetromino)
                lines_cleared = self.grid.clear_lines()
                for player in self.players:
                    player.update_score(lines_cleared)
                self.current_tetromino = self.new_tetromino()

    def render(self, screen):
        screen.fill((0, 0, 0))
        for i, row in enumerate(self.grid.grid):
            for j, value in enumerate(row):
                if value:
                    pygame.draw.rect(screen, COLORS[value], (j * BLOCK_SIZE, i * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        for player in self.players:
            score_text = f"Player {player.player_id + 1} Score: {player.score}"
            font = pygame.font.Font(None, 36)
            text = font.render(score_text, True, (255, 255, 255))
            screen.blit(text, (10, 10 + player.player_id * 30))

        pygame.display.flip()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

