        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Tetris for Three Players")
        self.clock = pygame.time.Clock()
        self.game = TetrisGame()

    def draw_grid(self):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[self.game.grid[y][x]]
                pygame.draw.rect(self.screen, color, (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 0)

    def draw_tetromino(self):
        for y, row in enumerate(self.game.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    color = COLORS[self.game.current_tetromino.color]
                    pygame.draw.rect(self.screen, color, ((self.game.current_tetromino.x + x) * BLOCK_SIZE, (self.game.current_tetromino.y + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 0)

    def draw_scores(self):
        font = pygame.font.Font(None, 36)
        for i in range(3):
            score_text = font.render(f"Player {i + 1}: {self.game.score[i]} (Contribution: {self.game.player_contributions[i]})", True, (255, 255, 255))
            self.screen.blit(score_text, (10, 10 + i * 30))

    def run(self):
        while True:
            self.screen.fill((0, 0, 0))
            self.draw_grid()
            self.draw_tetromino()
            self.draw_scores()
            pygame.display.flip()
            self.game.drop_tetromino()

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    return
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT and not self.game.check_collision(offset_x=-1):
                        self.game.current_tetromino.x -= 1
                    if event.key == pygame.K_RIGHT and not self.game.check_collision(offset_x=1):
                        self.game.current_tetromino.x += 1
                    if event.key == pygame.K_DOWN:
                        self.game.drop_tetromino()
                    if event.key == pygame.K_UP:
                        self.game.current_tetromino.rotate()
                        if self.game.check_collision():
