    (255, 165, 0),  # Orange
    (128, 0, 128),  # Purple
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS[1:])
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class TetrisGame:
    def __init__(self):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = [0, 0, 0]
        self.player_contributions = [0, 0, 0]
        self.current_player = 0

    def collide(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if (self.current_tetromino.x + x < 0 or
                        self.current_tetromino.x + x >= GRID_WIDTH or
                        self.current_tetromino.y + y >= GRID_HEIGHT or
                        self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x]):
                        return True
        return False

    def merge(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x] = self.current_tetromino.color
        self.clear_lines()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(GRID_HEIGHT):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        self.score[self.current_player] += lines_cleared
        self.player_contributions[self.current_player] += lines_cleared

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def update(self):
        self.current_tetromino.y += 1
        if self.collide():
            self.current_tetromino.y -= 1
            self.merge()
            self.current_tetromino = Tetromino()
            if self.collide():
                self.reset_game()

    def reset_game(self):
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.score = [0, 0, 0]
        self.player_contributions = [0, 0, 0]
        self.current_player = 0

