import pygame
import random

# Constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
GRID_SIZE = 30
GRID_WIDTH = SCREEN_WIDTH // GRID_SIZE
GRID_HEIGHT = SCREEN_HEIGHT // GRID_SIZE
FPS = 10

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        self.board = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.score = [0, 0, 0]
        self.player_turn = 0

    def valid_position(self, shape, offset_x, offset_y):
        for y, row in enumerate(shape):
            for x, cell in enumerate(row):
                if cell:
                    if (x + offset_x < 0 or x + offset_x >= GRID_WIDTH or
                            y + offset_y >= GRID_HEIGHT or
                            self.board[y + offset_y][x + offset_x]):
                        return False
        return True

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_tetromino.color
        self.clear_lines()
        self.current_tetromino = Tetromino()

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.board) if all(row)]
        for i in lines_to_clear:
            del self.board[i]
            self.board.insert(0, [0] * GRID_WIDTH)
            self.score[self.player_turn] += 100

    def switch_player(self):
        self.player_turn = (self.player_turn + 1) % 3

    def draw(self, screen):
        for y, row in enumerate(self.board):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, cell, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE))
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(screen, self.current_tetromino.color, ((x + self.current_tetromino.x) * GRID_SIZE, (y + self.current_tetromino.y) * GRID_SIZE, GRID_SIZE, GRID_SIZE))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.game = Game()
        self.running = True

    def run(self):
        while self.running:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(FPS)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    if self.game.valid_position(self.game.current_tetromino.shape, self.game.current_tetromino.x - 1, self.game.current_tetromino.y):
                        self.game.current_tetromino.x -= 1
                if event.key == pygame.K_RIGHT:
                    if self.game.valid_position(self.game.current_tetromino.shape, self.game.current_tetromino.x + 1, self.game.current_tetromino.y):
                        self.game.current_tetromino.x += 1
                if event.key == pygame.K_DOWN:
                    if self.game.valid_position(self.game.current_tetromino.shape, self.game.current_tetromino.x, self.game.current_tetromino.y + 1):
                        self.game.current_tetromino.y += 1
                if event.key == pygame.K_UP:
                    self.game.current_tetromino.rotate()
                    if not self.game.valid_position(self.game.current_tetromino.shape, self.game.current_tetromino.x, self.game.current_tetromino.y):
                        self.game.current_tetromino.rotate()  # Rotate back

    def update(self):
        if self.game.valid_position(self.game.current_tetromino.shape, self.game.current_tetromino.x, self.game.current_tetromino.y + 1):
            self.game.current_tetromino.y += 1
        else:
            self.game.merge_tetromino()
            self.game.switch_player()

    def draw(self):
        self.screen.fill((0, 0, 0))
        self.game.draw(self.screen)
        pygame.display.flip()

if __name__ == "__main__":
    TetrisGame().run()
    pygame.quit()

