FPS = 60

# Colors
COLORS = [
    (0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
    (255, 255, 0), (255, 165, 0), (128, 0, 128), (0, 255, 255)
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]]   # J
]

class Tetromino:
    def __init__(self, shape):
        self.shape = shape
        self.color = random.choice(COLORS[1:])
        self.x = BOARD_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Board:
    def __init__(self):
        self.grid = [[0] * BOARD_WIDTH for _ in range(BOARD_HEIGHT)]
        self.score = 0

    def clear_lines(self):
        lines_to_clear = [i for i, row in enumerate(self.grid) if all(row)]
        for i in lines_to_clear:
            del self.grid[i]
            self.grid.insert(0, [0] * BOARD_WIDTH)
            self.score += 100

    def add_tetromino(self, tetromino):
        for i, row in enumerate(tetromino.shape):
            for j, value in enumerate(row):
                if value:
                    self.grid[tetromino.y + i][tetromino.x + j] = 1

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.board = Board()
        self.tetromino = Tetromino(random.choice(SHAPES))
        self.running = True

    def draw_grid(self):
        for y in range(BOARD_HEIGHT):
            for x in range(BOARD_WIDTH):
                color = COLORS[self.board.grid[y][x]]
                pygame.draw.rect(self.screen, color, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE), 0)

    def run(self):
        while self.running:
            self.screen.fill((0, 0, 0))
            self.draw_grid()
            self.handle_events()
            self.update()
            pygame.display.flip()
            self.clock.tick(FPS)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.tetromino.x -= 1
                if event.key == pygame.K_RIGHT:
                    self.tetromino.x += 1
                if event.key == pygame.K_DOWN:
                    self.tetromino.y += 1
                if event.key == pygame.K_UP:
                    self.tetromino.rotate()

    def update(self):
        self.tetromino.y += 1
        if self.check_collision():
            self.tetromino.y -= 1
            self.board.add_tetromino(self.tetromino)
            self.board.clear_lines()
            self.tetromino = Tetromino(random.choice(SHAPES))

    def check_collision(self):
        for i, row in enumerate(self.tetromino.shape):
            for j, value in enumerate(row):
                if value:
                    if (self.tetromino.x + j < 0 or
                        self.tetromino.x + j >= BOARD_WIDTH or
                        self.tetromino.y + i >= BOARD_HEIGHT or
                        self.board.grid[self.tetromino.y + i][self.tetromino.x + j]):
                        return True
        return False

