SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
]

class Tetromino:
    def __init__(self):
        self.shape = random.choice(SHAPES)
        self.color = random.choice(COLORS)
        self.x = GRID_WIDTH // 2 - len(self.shape[0]) // 2
        self.y = 0

    def rotate(self):
        self.shape = [list(row) for row in zip(*self.shape[::-1])]

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        self.clock = pygame.time.Clock()
        self.running = True
        self.grid = [[0] * GRID_WIDTH for _ in range(GRID_HEIGHT)]
        self.current_tetromino = Tetromino()
        self.scores = [0, 0, 0]  # Scores for three players
        self.current_player = 0

    def draw_grid(self):
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = COLORS[self.grid[y][x]]
                pygame.draw.rect(self.screen, color, (x * GRID_SIZE, y * GRID_SIZE, GRID_SIZE, GRID_SIZE), 0)

    def draw_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    pygame.draw.rect(self.screen, self.current_tetromino.color, 
                                     ((self.current_tetromino.x + x) * GRID_SIZE, 
                                      (self.current_tetromino.y + y) * GRID_SIZE, 
                                      GRID_SIZE, GRID_SIZE), 0)

    def check_collision(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    if (self.current_tetromino.x + x < 0 or
                        self.current_tetromino.x + x >= GRID_WIDTH or
                        self.current_tetromino.y + y >= GRID_HEIGHT or
                        self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x]):
                        return True
        return False

    def merge_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, value in enumerate(row):
                if value:
                    self.grid[self.current_tetromino.y + y][self.current_tetromino.x + x] = COLORS.index(self.current_tetromino.color)

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        self.scores[self.current_player] += lines_cleared

    def switch_player(self):
        self.current_player = (self.current_player + 1) % 3

    def run(self):
        while self.running:
            self.screen.fill((255, 255, 255))
            self.draw_grid()
            self.draw_tetromino()
            self.clear_lines()

            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.running = False
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT:
                        self.current_tetromino.x -= 1
                        if self.check_collision():
                            self.current_tetromino.x += 1
                    if event.key == pygame.K_RIGHT:
                        self.current_tetromino.x += 1
                        if self.check_collision():
                            self.current_tetromino.x -= 1
                    if event.key == pygame.K_DOWN:
                        self.current_tetromino.y += 1
                        if self.check_collision():
                            self.current_tetromino.y -= 1
                    if event.key == pygame.K_UP:
                        self.current_tetromino.rotate()
                        if self.check_collision():
                            self.current_tetromino.rotate()
                            self.current_tetromino.rotate()
                            self.current_tetromino.rotate()

            self.current_tetromino.y += 1
            if self.check_collision():
                self.current_tetromino.y -= 1
                self.merge_tetromino()
                self.current_tetromino = Tetromino()
                if self.check_collision():
                    self.running = False  # Game over
                self.switch_player()

            pygame.display.flip()
            self.clock.tick(FPS)

if __name__ == "__main__":
    game = Game()
    game.run()
    pygame.quit()

